// Браузер создаёт Event объект
// event.target = <li>Элемент 2</li>

// Фаза capturing: document → html → body → div#app → ul#list → li
// (обработчики с { capture: true } вызываются здесь)

// Событие достигает target (li)
// Обработчики на самом li вызываются здесь
// (как capture так и bubble обработчики)

// Событие всплывает: li → ul#list → div#app → body → html → document

list.addEventListener('click', (e) => {
  // e.target = li (куда кликнули)
  // e.currentTarget = ul (где обработчик)

  if (e.target.classList.contains('item')) {
    console.log('Клик на элемент!')
  }
})
